  let customCacheKey = '';
  if (cacheKeyParam) {
    // Sanitize cache key: allow only alphanumeric, hyphens, underscores, max 256 chars
    const sanitized = cacheKeyParam.replace(/[^a-zA-Z0-9\-_]/g, '').substring(0, 256);
    if (sanitized.length > 0) {
      customCacheKey = sanitized;
    }
  }
  
  // Remove cache control params from URL for origin request
  url.searchParams.delete('ttl');
  url.searchParams.delete('cache_key');
  
  // Construct cache key
  const baseCacheKey = url.toString();
  const cacheKey = customCacheKey 
    ? `${baseCacheKey}:custom:${customCacheKey}`
    : baseCacheKey;
  
  // Create cache key request object
  const cacheKeyRequest = new Request(cacheKey, {
    method: 'GET',
    headers: request.headers
  });
  
  const cache = caches.default;
  
  // Try to get from cache
  let response = await cache.match(cacheKeyRequest);
  
  if (response) {
    // Return cached response with cache status header
    const newResponse = new Response(response.body, response);
    newResponse.headers.set('X-Cache-Status', 'HIT');
    return newResponse;
  }
  
  // Fetch from origin
  const originRequest = new Request(url.toString(), {
    method: request.method,
    headers: request.headers,
    body: request.method !== 'GET' && request.method !== 'HEAD' ? request.body : null,
    redirect: 'follow'
  });
  
  response = await fetch(originRequest);
  
  // Only cache successful GET requests
  if (request.method === 'GET' && response.status === 200) {
    // Clone response for caching
    const responseToCache = response.clone();
    
    // Set cache control headers
    const cacheHeaders = new Headers(responseToCache.headers);
    cacheHeaders.set('Cache-Control', `public, max-age=${ttl}`);
    cacheHeaders.set('X-Cache-Status', 'MISS');
    
    // Create response with cache headers
    const cachedResponse = new Response(responseToCache.body, {
      status: responseToCache.status,
      statusText: responseToCache.statusText,
      headers: cacheHeaders
    });
    
    // Store in cache (non-blocking)
    event.waitUntil(cache.put(cacheKeyRequest, cachedResponse.clone()));
    
    return cachedResponse;
  }
  
  // Return non-cacheable response
  const newResponse = new Response(response.body, response);
